import { useEffect, useState } from 'react';
import api from '../../services/api';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { FiPackage, FiShoppingCart, FiTrendingUp, FiAlertTriangle, FiArrowRight } from 'react-icons/fi';

export default function Dashboard() {
  const [productosBajoStock, setProductosBajoStock] = useState([]);
  const [ultimasVentas, setUltimasVentas] = useState([]);
  const [stats, setStats] = useState({ totalProductos: 0, ventasHoy: 0, ingresosHoy: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [stockRes, ventasRes, productosRes] = await Promise.all([
          api.get('/reportes/stock-bajo'),
          api.get('/ventas'),
          api.get('/productos')
        ]);
        
        setProductosBajoStock(stockRes.data);
        setUltimasVentas(ventasRes.data.slice(0, 5));
        
        const hoy = new Date().toISOString().split('T')[0];
        const ventasHoy = ventasRes.data.filter(v => v.fecha.split('T')[0] === hoy);
        const ingresosHoy = ventasHoy.reduce((sum, v) => sum + parseFloat(v.total), 0);
        
        setStats({
          totalProductos: productosRes.data.length,
          ventasHoy: ventasHoy.length,
          ingresosHoy: ingresosHoy
        });
      } catch (error) {
        toast.error('Error al cargar datos del dashboard');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  const statsCards = [
    { title: 'Productos', value: stats.totalProductos, icon: FiPackage, color: 'bg-blue-500', link: '/productos' },
    { title: 'Ventas hoy', value: stats.ventasHoy, icon: FiShoppingCart, color: 'bg-green-500', link: '/ventas' },
    { title: 'Ingresos hoy', value: `$${stats.ingresosHoy.toFixed(2)}`, icon: FiTrendingUp, color: 'bg-purple-500', link: '/ventas' },
    { title: 'Stock bajo', value: productosBajoStock.length, icon: FiAlertTriangle, color: 'bg-red-500', link: '/productos' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold text-gray-800">Panel de Control</h1>
        <div className="text-sm text-gray-500">
          {new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
        </div>
      </div>
      
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {statsCards.map((stat, idx) => {
          const Icon = stat.icon;
          return (
            <Link to={stat.link} key={idx} className="block transform hover:scale-105 transition-all duration-200">
              <div className="card p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-gray-500 text-sm">{stat.title}</p>
                    <p className="text-3xl font-bold text-gray-800 mt-2">{stat.value}</p>
                  </div>
                  <div className={`${stat.color} p-3 rounded-full text-white`}>
                    <Icon className="text-2xl" />
                  </div>
                </div>
              </div>
            </Link>
          );
        })}
      </div>
      
      {/* Two column layout */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Productos con stock bajo */}
        <div className="card">
          <div className="bg-gradient-to-r from-red-500 to-red-600 px-6 py-4">
            <h2 className="text-xl font-semibold text-white flex items-center">
              <FiAlertTriangle className="mr-2" /> Productos con stock bajo
            </h2>
          </div>
          <div className="p-6">
            {productosBajoStock.length === 0 ? (
              <p className="text-gray-500 text-center py-8">✅ No hay productos con stock bajo</p>
            ) : (
              <ul className="divide-y divide-gray-200">
                {productosBajoStock.map(p => (
                  <li key={p.id} className="py-3 flex justify-between items-center">
                    <div>
                      <p className="font-medium text-gray-800">{p.nombre}</p>
                      <p className="text-sm text-gray-500">Código: {p.codigo}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-red-600 font-bold">{p.stock_actual} unidades</p>
                      <p className="text-xs text-gray-500">Mínimo: {p.stock_minimo}</p>
                    </div>
                  </li>
                ))}
              </ul>
            )}
            <Link to="/productos" className="mt-4 inline-flex items-center text-primary-600 hover:text-primary-700">
              Ver todos los productos <FiArrowRight className="ml-1" />
            </Link>
          </div>
        </div>
        
        {/* Últimas ventas */}
        <div className="card">
          <div className="bg-gradient-to-r from-green-500 to-green-600 px-6 py-4">
            <h2 className="text-xl font-semibold text-white flex items-center">
              <FiTrendingUp className="mr-2" /> Últimas ventas
            </h2>
          </div>
          <div className="p-6">
            {ultimasVentas.length === 0 ? (
              <p className="text-gray-500 text-center py-8">No hay ventas registradas</p>
            ) : (
              <ul className="divide-y divide-gray-200">
                {ultimasVentas.map(v => (
                  <li key={v.id} className="py-3 flex justify-between items-center">
                    <div>
                      <p className="font-medium text-gray-800">{v.cliente_nombre}</p>
                      <p className="text-sm text-gray-500">{new Date(v.fecha).toLocaleDateString()}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-green-600 font-bold">${parseFloat(v.total).toFixed(2)}</p>
                      <p className="text-xs text-gray-500">ID: {v.id}</p>
                    </div>
                  </li>
                ))}
              </ul>
            )}
            <Link to="/ventas" className="mt-4 inline-flex items-center text-primary-600 hover:text-primary-700">
              Ver historial completo <FiArrowRight className="ml-1" />
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}
